import { useLayoutEffect, useRef } from 'react';
import gsap from 'gsap';

export function GsapSequence() {
  const root = useRef<HTMLDivElement>(null);
  useLayoutEffect(() => {
    const ctx = gsap.context(() => {
      gsap.from('[data-anim]', { opacity: 0, y: 16, stagger: 0.04, duration: 0.24, ease: 'power2.out' });
    }, root);
    return () => ctx.revert();
  }, []);
  return <div ref={root} data-anim>GSAP for character-by-character text reveal</div>;
}

